import{c as n,Q as t,j as a,m as r}from"./chunks/framework.BPKcPtvA.js";const o="/assets/ldk-peer-management.3L1BTg7t.svg",s="/assets/ldk-peer-management-dark.Bwn2Zkwb.svg",u=JSON.parse('{"title":"Peer Management","description":"","frontmatter":{},"headers":[],"relativePath":"introduction/peer-management.md","filePath":"introduction/peer-management.md","lastUpdated":1780664783000}'),i={name:"introduction/peer-management.md"};function l(c,e,d,g,h,p){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="peer-management" tabindex="-1">Peer Management <a class="header-anchor" href="#peer-management" aria-label="Permalink to &quot;Peer Management&quot;">​</a></h1><img class="light-only" src="'+o+'" alt="Peer Management"><img class="dark-only" src="'+s+'" alt="Peer Management"><p>One of the first things you&#39;ll need to do when building your own Lightning node is connect to a peer. In LDK this is handled by the <a href="https://docs.rs/lightning/*/lightning/ln/peer_handler/struct.PeerManager.html" target="_blank" rel="noreferrer"><code>PeerManager</code></a>.</p><p>The <code>PeerManager</code> has two dependencies:</p><ul><li>A <a href="https://docs.rs/lightning/*/lightning/ln/channelmanager/index.html" target="_blank" rel="noreferrer"><code>ChannelManager</code></a> that enables it to notify peers when it wants to do things such as open channels.</li><li>A <a href="https://docs.rs/lightning/*/lightning/routing/gossip/struct.P2PGossipSync.html" target="_blank" rel="noreferrer"><code>P2PGossipSync</code></a> that understands when peers you are connected to send you gossip messages, enables you to forward messages, announce channel opens and more.</li></ul><p>Since LDK knows nothing about your networking stack, you&#39;ll need to implement your own networking logic in order to connect to peers on the network. Provide LDK with raw TCP/IP socket data and the library will handle the rest for you.</p><p>LDK also handles a number of background tasks that need to happen periodically via <a href="https://docs.rs/lightning-background-processor/*/lightning_background_processor/struct.BackgroundProcessor.html" target="_blank" rel="noreferrer"><code>BackgroundProcessor</code></a></p><div class="tip custom-block"><p class="custom-block-title">Default Implementation</p><p>If you are developing in a Rust <a href="https://tokio.rs/" target="_blank" rel="noreferrer">Tokio</a> environment, LDK ships with a socket handling <a href="https://docs.rs/lightning-net-tokio/*/lightning_net_tokio/" target="_blank" rel="noreferrer">crate</a> that let&#39;s you easily create new connections with peers.</p></div>',9)])])}const _=n(i,[["render",l]]);export{u as __pageData,_ as default};
